  "title": "S3 लाइफसाइकल मैनेजमेंट",
  "group": "S3 लाइफसाइकल",
  "options": [
    {
      "text": "ऑब्जेक्ट्स को मैन्युअली मूव करें",
      "hint": "क्या यह स्केलेबल है?"
    },
    {
      "text": "ऑब्जेक्ट्स को स्टोरेज क्लासेस के बीच ऑटोमैटिकली ट्रांजिशन करें",
      "hint": "AWS का मुख्य फीचर यही है।"
    },
    {
      "text": "पुराने ऑब्जेक्ट्स को कभी डिलीट न करें",
      "hint": "कॉस्ट बढ़ जाएगी!"
    },
    {
      "text": "सब कुछ स्टैंडर्ड क्लास में स्टोर करें",
      "hint": "क्या यह कॉस्ट-इफेक्टिव है?"
    }
  ],
  "questionProse": [
    "S3 लाइफसाइकल मैनेजमेंट असल में क्या करता है?"
  ],
  "explanationProse": [
    "लाइफसाइकल मैनेजमेंट का असली मकसद है कॉस्ट और एफिशिएंसी को बैलेंस करना:\n  - यह ऑब्जेक्ट्स को स्टोरेज क्लासेस के बीच ऑटोमैटिकली ट्रांजिशन करता है\n  - कम इस्तेमाल होने वाले डेटा को सस्ते स्टोरेज में मूव कर देता है\n  - ऑब्जेक्ट एक्सपायरेशन के लिए रूल्स सेट करने देता है\n  - स्टोरेज कॉस्ट को ऑप्टिमाइज़ करता है\n  - मैन्युअल मैनेजमेंट का ओवरहेड खत्म कर देता है\n\n  [S3 लाइफसाइकल रूल्स](https://docs.aws.amazon.com/AmazonS3/latest/userguide/lifecycle-configuration-examples.html)"
  ]
}
